function solve(n, edges, k) {
    if (edges.length === 0) {
        return 0;
    }
    edges.sort((a, b) => a[2] - b[2]);
    const maxTime = edges[edges.length - 1][2];
    let low = 0;
    let high = maxTime;
    let answer = maxTime;

    function countComponents(t) {
        const parent = Array(n).fill().map((_, i) => i);
        function find(u) {
            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }
        function union(u, v) {
            const rootU = find(u);
            const rootV = find(v);
            if (rootU !== rootV) {
                parent[rootV] = rootU;
            }
        }
        for (const [u, v, time] of edges) {
            if (time > t) {
                union(u, v);
            }
        }
        const roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const comp = countComponents(mid);
        if (comp >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return answer;
}
